import { Redis } from "@upstash/redis";
import { env } from "@/env";
import { logger } from "@/lib/logger";

let redisClient: Redis | null = null;
let isInitialized = false;

if (env.NEXT_PUBLIC_FEATURE_REDIS_ENABLED) {
  // Explicitly check required env vars for type safety
  if (!env.UPSTASH_REDIS_REST_URL || !env.UPSTASH_REDIS_REST_TOKEN) {
    if (!isInitialized) {
      logger.error(
        "❌ Redis feature is enabled, but UPSTASH_REDIS_REST_URL or UPSTASH_REDIS_REST_TOKEN are missing."
      );
      isInitialized = true;
    }
  } else {
    try {
      redisClient = new Redis({
        url: env.UPSTASH_REDIS_REST_URL,
        token: env.UPSTASH_REDIS_REST_TOKEN,
      });
      if (!isInitialized) {
        logger.info("✅ Redis Client Initialized (from redis-service)");
        isInitialized = true;
      }
    } catch (error) {
      if (!isInitialized) {
        logger.error("❌ Failed to initialize Redis client (from redis-service):", error);
        isInitialized = true;
      }
      // Keep redisClient as null if initialization fails
    }
  }
}

/**
 * The initialized Upstash Redis client instance.
 * Will be `null` if Redis is disabled or fails to initialize.
 */
export { redisClient };

import { env } from "@/env";
import { logger } from "@/lib/logger";
import { metrics, metricsService } from "./metrics-service";
import { redisClient as redis } from "./redis-service"; // Import the shared client

export interface CacheConfig {
  ttl?: number; // Time to live in seconds
  staleWhileRevalidate?: number; // Additional time to serve stale content while revalidating
}

export interface CacheEntry<T> {
  data: T;
  createdAt: number;
  updatedAt: number;
}

export class CacheService {
  private readonly prefix = "cache";
  private readonly enabled = !!redis;

  /**
   * Gets a value from cache
   */
  async get<T>(key: string): Promise<T | null> {
    if (!this.enabled) return null;

    let rawData: string | Record<string, unknown> | null = null;
    try {
      const startTime = Date.now();
      rawData = await redis!.get(`${this.prefix}:${key}`);
      await metricsService.recordTiming(metrics.cache.latency, startTime);

      if (rawData === null) {
        await metricsService.incrementCounter(metrics.cache.misses);
        return null;
      }

      // Ensure data is a string before parsing
      if (typeof rawData !== "string") {
        logger.error("Invalid data type received from cache", {
          key,
          type: typeof rawData,
        });
        await metricsService.incrementCounter(metrics.cache.errors);
        return null;
      }

      // Now parse the string data
      try {
        const parsedData = JSON.parse(rawData) as CacheEntry<T>;
        await metricsService.incrementCounter(metrics.cache.hits);
        // Check if the parsed data has the expected structure (basic check)
        if (typeof parsedData === "object" && parsedData !== null && "data" in parsedData) {
          return parsedData.data;
        }

        // If structure is invalid, log error, delete entry, and return null
        logger.error("Parsed cache data lacks expected structure", { key });
        await metricsService.incrementCounter(metrics.cache.errors);
        await this.delete(key); // Delete invalid entry
        return null;
      } catch (parseError) {
        logger.error("Failed to parse cache data", { key, data: rawData, error: parseError });
        await metricsService.incrementCounter(metrics.cache.errors);
        await this.delete(key); // Delete invalid entry
        return null;
      }
    } catch (error) {
      logger.error("Failed to get from cache (Redis operation error)", { key, error });
      await metricsService.incrementCounter(metrics.cache.errors);
      return null;
    }
  }

  /**
   * Sets a value in cache
   */
  async set<T>(key: string, value: T, config: CacheConfig = {}): Promise<void> {
    if (!this.enabled) return;

    try {
      const entry: CacheEntry<T> = {
        data: value,
        createdAt: Date.now(),
        updatedAt: Date.now(),
      };

      if (config.ttl) {
        await redis!.setex(`${this.prefix}:${key}`, config.ttl, JSON.stringify(entry));
      } else {
        await redis!.set(`${this.prefix}:${key}`, JSON.stringify(entry));
      }
    } catch (error) {
      logger.error("Failed to set cache", { key, error });
      await metricsService.incrementCounter(metrics.cache.errors);
    }
  }

  /**
   * Deletes a value from cache
   */
  async delete(key: string): Promise<void> {
    if (!this.enabled) return;

    try {
      await redis!.del(`${this.prefix}:${key}`);
    } catch (error) {
      logger.error("Failed to delete from cache", { key, error });
      await metricsService.incrementCounter(metrics.cache.errors);
    }
  }

  /**
   * Gets a value from cache or computes it if not found
   */
  async getOrSet<T>(key: string, factory: () => Promise<T>, config: CacheConfig = {}): Promise<T> {
    // If caching is disabled, just compute the value
    if (!this.enabled) {
      return factory();
    }

    const cached = await this.get<CacheEntry<T>>(key);

    // If we have a cached value and it's not stale, return it
    if (cached && this.isValid(cached, config)) {
      return cached.data;
    }

    // If we have a stale value and staleWhileRevalidate is set,
    // revalidate in the background and return stale data
    if (cached && config.staleWhileRevalidate && this.isStale(cached, config)) {
      void this.revalidate(key, factory, config);
      return cached.data;
    }

    // Otherwise, compute the value and cache it
    const value = await factory();
    await this.set(key, value, config);
    return value;
  }

  /**
   * Checks if a cached entry is still valid
   */
  private isValid(entry: CacheEntry<unknown>, config: CacheConfig): boolean {
    if (!config.ttl) return true;
    const age = Date.now() - entry.updatedAt;
    return age < config.ttl * 1000;
  }

  /**
   * Checks if a cached entry is stale but still usable
   */
  private isStale(entry: CacheEntry<unknown>, config: CacheConfig): boolean {
    if (!config.ttl || !config.staleWhileRevalidate) return false;
    const age = Date.now() - entry.updatedAt;
    return age >= config.ttl * 1000 && age < (config.ttl + config.staleWhileRevalidate) * 1000;
  }

  /**
   * Revalidates a cached value in the background
   */
  private async revalidate<T>(
    key: string,
    factory: () => Promise<T>,
    config: CacheConfig
  ): Promise<void> {
    try {
      const value = await factory();
      await this.set(key, value, config);
    } catch (error) {
      logger.error("Failed to revalidate cache", { key, error });
      await metricsService.incrementCounter(metrics.cache.errors);
    }
  }
}

export const cacheService = new CacheService();

// Common cache configurations
export const cacheConfigs = {
  short: {
    ttl: 60, // 1 minute
    staleWhileRevalidate: 60, // 1 minute
  },
  medium: {
    ttl: 300, // 5 minutes
    staleWhileRevalidate: 300, // 5 minutes
  },
  long: {
    ttl: 3600, // 1 hour
    staleWhileRevalidate: 1800, // 30 minutes
  },
  day: {
    ttl: 86400, // 24 hours
    staleWhileRevalidate: 3600, // 1 hour
  },
} as const;

import { Ratelimit } from "@upstash/ratelimit";
import { Redis } from "@upstash/redis";
import { rateLimits as globalRateLimits } from "@/config/rate-limits";
import { env } from "@/env";
import { logger } from "@/lib/logger";
import { ErrorService } from "./error-service";

// Try to create Redis instance if configured
let redis: Redis | null = null;
let isInitialized = false;

try {
  if (env.UPSTASH_REDIS_REST_URL && env.UPSTASH_REDIS_REST_TOKEN) {
    redis = new Redis({
      url: env.UPSTASH_REDIS_REST_URL,
      token: env.UPSTASH_REDIS_REST_TOKEN,
    });
    if (!isInitialized) {
      logger.info("Redis rate limiting initialized");
      isInitialized = true;
    }
  }
} catch (error) {
  if (!isInitialized) {
    logger.error("Failed to initialize Redis for rate limiting", { error });
    isInitialized = true;
  }
}

export interface RateLimitConfig {
  requests: number;
  duration: number; // in seconds
  blockDuration?: number; // in seconds
}

export class RateLimitService {
  private limiters = new Map<string, Ratelimit>();
  private readonly enabled = !!redis;

  /**
   * Gets or creates a rate limiter for a specific key
   */
  private getLimiter(key: string, config: RateLimitConfig): Ratelimit {
    if (!this.enabled) {
      throw new Error("Rate limiting is not enabled");
    }

    const existingLimiter = this.limiters.get(key);
    if (existingLimiter) {
      return existingLimiter;
    }

    const limiter = new Ratelimit({
      redis: redis!,
      limiter: Ratelimit.slidingWindow(config.requests, `${config.duration}s`),
      analytics: true,
      prefix: `ratelimit:${key}`,
    });

    this.limiters.set(key, limiter);
    return limiter;
  }

  /**
   * Checks if a request should be rate limited
   */ async checkLimit(identifier: string, action: string, config: RateLimitConfig): Promise<void> {
    // Skip rate limiting if Redis is not available
    if (!this.enabled) {
      logger.debug("Rate limiting disabled, skipping check", {
        identifier,
        action,
      });
      return;
    }

    const limiter = this.getLimiter(`${action}:${identifier}`, config);
    const { success, limit, reset, remaining } = await limiter.limit(identifier);

    if (!success) {
      ErrorService.throwRateLimited("Too many requests", {
        limit,
        reset,
        remaining,
      });
    }
  }

  /**
   * Gets the current rate limit status
   */ async getStatus(
    identifier: string,
    action: string
  ): Promise<{
    limit: number;
    remaining: number;
    reset: number;
  }> {
    if (!this.enabled) {
      return {
        limit: Number.POSITIVE_INFINITY,
        remaining: Number.POSITIVE_INFINITY,
        reset: 0,
      };
    }

    const key = `ratelimit:${action}:${identifier}`;
    // @ts-expect-error
    const [[limit], [remaining], [reset]] = await redis!
      .pipeline()
      .get(`${key}:limit`)
      .get(`${key}:remaining`)
      .get(`${key}:reset`)
      .exec();

    return {
      limit: Number(limit) || 0,
      remaining: Number(remaining) || 0,
      reset: Number(reset) || 0,
    };
  }

  /**
   * Resets rate limit for a specific identifier and action
   */ async resetLimit(identifier: string, action: string): Promise<void> {
    if (!this.enabled) return;

    const key = `ratelimit:${action}:${identifier}`;
    await redis!.pipeline().del(`${key}:limit`).del(`${key}:remaining`).del(`${key}:reset`).exec();
  }
}

export const rateLimitService = new RateLimitService();

// Common rate limit configurations
export const rateLimits = globalRateLimits;

export const rateLimits = {
  api: {
    default: {
      requests: 100,
      duration: 60,
    },
    auth: {
      requests: 10,
      duration: 60 * 5,
    },
  },
  web: {
    default: {
      requests: 50,
      duration: 60,
    },
    forms: {
      requests: 20,
      duration: 60 * 2,
    },
  },
  deployments: {
    // Allow 5 deployments per hour per user
    create: {
      requests: 5,
      duration: 60 * 60, // 1 hour
    },
    // Allow 30 status checks per minute
    status: {
      requests: 30,
      duration: 60, // 1 minute
    },
  },
  importPayments: {
    requests: 5,
    duration: 60 * 30,
  },
  createPayment: {
    requests: 10,
    duration: 60 * 5,
  },
  getPayments: {
    requests: 20,
    duration: 60 * 5,
  },
  getAllPayments: {
